script:
frappe.ui.form.on('Patient Bill', {
	onload(frm) {
		set_appointment_query(frm);
	},

	patient(frm) {
		frm.set_value("patient_appointment", null);
		set_appointment_query(frm);
	}
})

function set_appointment_query(frm) {
	frm.set_query("patient_appointment", function () {
		if (!frm.doc.patient) {
			return {};
		}

		return {
			filters: {
				patient: frm.doc.patient,
				invoiced: 0
			}
		};
	});
}

frappe.ui.form.on('Vital Signs', {
	onload(frm) {
		set_appointment_query(frm);
	},

	patient(frm) {
		frm.set_value("patient_appointment", null);
		set_appointment_query(frm);
	}
})

function set_appointment_query(frm) {
	frm.set_query("patient_appointment", function () {
		if (!frm.doc.patient) {
			return {};
		}

		return {
			filters: {
				patient: frm.doc.patient
			}
		};
	});
}
